SELECT order_id, MAX(status_date) AS latest_status_date
FROM order_status
GROUP BY order_id;

SELECT SUM(sales) AS total_sales
FROM sales
WHERE order_id = '0';

SELECT COUNT(DISTINCT o.customer_id) AS customer_count
FROM orders o
WHERE o.region = 'Central US';

SELECT customer_name 
FROM customers 
ORDER BY customer_name;

SELECT COUNT(order_id) AS delivered_orders
FROM order_status
WHERE status = 'Delivered';

SELECT customer_name
FROM customers
WHERE customer_id = '1';
